mapper.sql:
FROM products p JOIN categories c ON c.id = p.category_id LEFT JOIN ( SELECT po.product_id, SUM(pc.quantity) AS total_quantity FROM purchases pc JOIN product_options po ON po.id = pc.product_option_id GROUP BY po.product_id ) purchase_stat ON purchase_stat.product_id = p.id LEFT JOIN product_pictures pp ON pp.id = ( SELECT MIN(pp2.id) FROM product_pictures pp2 WHERE pp2.product_id = p.id ) LEFT JOIN ( SELECT po.product_id, MIN(hp.hot_deal_price) AS sale_price, MAX(FLOOR((hp.original_price - hp.hot_deal_price) / hp.original_price * 100)) AS discount_rate FROM hot_deals h JOIN hot_deal_products hp ON hp.hot_deal_id = h.id JOIN product_options po ON po.id = hp.product_option_id WHERE h.status = 'ACTIVE' AND h.deleted_at IS NULL AND SYSTIMESTAMP BETWEEN h.starts_at AND h.ends_at GROUP BY po.product_id ) deal_stat ON deal_stat.product_id = p.id LEFT JOIN ( SELECT DISTINCT product_id FROM favorites WHERE user_id = #{userId} ) favorite_stat ON favorite_stat.product_id = p.id WHERE p.category_id = #{categoryId}
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
AND NVL(deal_stat.discount_rate, 0) >= #{minDiscountRate}
